// resourceIDFieldOverrides projects per-resource IDField (set by the profiler
// from x-resource-id or response-schema fallback) into a runtime lookup map.
// UpsertBatch consults this first so the templated path wins over the
// generic fallback list. Empty when no resource declared an override; the
// runtime fallback list still applies.
//
// Includes both flat resources and dependent (parent-child) resources so a
// child path-item annotated with x-resource-id resolves the same as a flat
// path-item.
var resourceIDFieldOverrides = map[string]string{
	"playlists": "id",
	"videos":    "id",
	"webhooks":  "id",
}

// genericIDFieldFallbacks is the runtime safety net for resources that did
// NOT receive a templated IDField. API-specific names belong in spec
// annotations (x-resource-id), not this list.
var genericIDFieldFallbacks = []string{"id", "ID", "name", "uuid", "slug", "key", "code", "uid"}

// UpsertBatch inserts or replaces multiple records in a single transaction
// and returns (stored, extractFailures, err). stored counts rows actually
// landed; extractFailures counts items that survived JSON unmarshal but had
// no extractable primary key (templated IDField AND generic fallback both
// missed). callers (sync.go.tmpl) compare these against len(items) to emit
// the per-item primary_key_unresolved warning and the F4b
// stored_count_zero_after_extraction probe.
//
// For resource types that have a domain-specific typed table, the per-item
// generic insert is followed by a dispatch to the matching upsert<Pascal>Tx
// inside the same transaction. Without that dispatch, paginated syncs would
// only populate the generic resources table — typed tables (and indexed
// columns like parent_id added by dependent-resource sync) would stay empty.
func (s *Store) UpsertBatch(resourceType string, items []json.RawMessage) (int, int, error) {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return 0, 0, fmt.Errorf("starting batch transaction: %w", err)
	}
	defer tx.Rollback()

	var stored, skippedCount, extractFailures int
	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			skippedCount++
			continue
		}
		// Templated IDField wins; generic fallback list runs second when
		// the override is empty OR the override field is absent on this
		// particular item (response shape mismatches happen even when the
		// spec declares x-resource-id).
		var id string
		if override, ok := resourceIDFieldOverrides[resourceType]; ok && override != "" {
			if v := lookupFieldValue(obj, override); v != nil {
				s := fmt.Sprintf("%v", v)
				if s != "" && s != "<nil>" {
					id = s
				}
			}
		}
		if id == "" {
			for _, key := range genericIDFieldFallbacks {
				if v := lookupFieldValue(obj, key); v != nil {
					s := fmt.Sprintf("%v", v)
					if s != "" && s != "<nil>" {
						id = s
						break
					}
				}
			}
		}
		if id == "" {
			skippedCount++
			extractFailures++
			continue
		}

		if err := s.upsertGenericResourceTx(tx, resourceType, id, item); err != nil {
			return 0, extractFailures, fmt.Errorf("upserting %s/%s: %w", resourceType, id, err)
		}

		switch resourceType {
		case "playlists_videos":
			if err := s.upsertPlaylistsVideosTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "clips":
			if err := s.upsertClipsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "collaborators":
			if err := s.upsertCollaboratorsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "duplicate":
			if err := s.upsertDuplicateTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "exports":
			if err := s.upsertExportsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "thumbnail":
			if err := s.upsertThumbnailTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "webhooks":
			if err := s.upsertWebhooksTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		}
		stored++
	}

	// Warn when most items in a batch lack an extractable ID — this likely
	// means the API uses a primary key field we don't recognize yet.
	if skippedCount > 0 && len(items) > 0 && skippedCount*2 > len(items) {
		fmt.Fprintf(os.Stderr, "warning: %d/%d %s items skipped (no extractable ID field found)\n", skippedCount, len(items), resourceType)
	}

	if err := tx.Commit(); err != nil {
		return 0, extractFailures, err
	}
	return stored, extractFailures, nil
}

func (s *Store) SaveSyncState(resourceType, cursor string, count int) error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	_, err := s.db.Exec(
		`INSERT INTO sync_state (resource_type, last_cursor, last_synced_at, total_count)
		 VALUES (?, ?, ?, ?)
		 ON CONFLICT(resource_type) DO UPDATE SET last_cursor = excluded.last_cursor,
		 last_synced_at = excluded.last_synced_at, total_count = excluded.total_count`,
		resourceType, cursor, time.Now(), count,
	)
	return err
}

func (s *Store) GetSyncState(resourceType string) (cursor string, lastSynced time.Time, count int, err error) {
	err = s.db.QueryRow(
		`SELECT last_cursor, last_synced_at, total_count FROM sync_state WHERE resource_type = ?`,
		resourceType,
	).Scan(&cursor, &lastSynced, &count)
	if err == sql.ErrNoRows {
		return "", time.Time{}, 0, nil
	}
	return
}

// SaveSyncCursor stores the pagination cursor for a resource type.
func (s *Store) SaveSyncCursor(resourceType, cursor string) error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	_, err := s.db.Exec(
		`INSERT INTO sync_state (resource_type, last_cursor, last_synced_at, total_count)
		 VALUES (?, ?, CURRENT_TIMESTAMP, 0)
		 ON CONFLICT(resource_type) DO UPDATE SET last_cursor = ?, last_synced_at = CURRENT_TIMESTAMP`,
		resourceType, cursor, cursor,
	)
	return err
}

// GetSyncCursor returns the last pagination cursor for a resource type.
func (s *Store) GetSyncCursor(resourceType string) string {
	var cursor sql.NullString
	s.db.QueryRow("SELECT last_cursor FROM sync_state WHERE resource_type = ?", resourceType).Scan(&cursor)
	if cursor.Valid {
		return cursor.String
	}
	return ""
}

// ListIDs returns all IDs from a resource's domain table, or from the generic
// resources table if no domain table exists. Used by dependent sync to iterate parents.
func (s *Store) ListIDs(resourceType string) ([]string, error) {
	// Defense-in-depth: this method composes resourceType into the SQL
	// table-name slot via fmt.Sprintf. All current callers route through
	// syncResourcePath, which whitelists three resources, but a future
	// caller could bypass that. Reject anything not in the schema.
	allowedResourceTables := map[string]bool{
		"playlists_videos": true,
		"clips":            true,
		"collaborators":    true,
		"duplicate":        true,
		"exports":          true,
		"thumbnail":        true,
		"webhooks":         true,
		"transcripts":      true,
		"resources":        true,
	}
	if !allowedResourceTables[resourceType] {
		return nil, fmt.Errorf("ListIDs: invalid resourceType %q", resourceType)
	}
	// Try domain table first (tables are named after the resource type)
	query := fmt.Sprintf("SELECT id FROM %s", resourceType)
	rows, err := s.db.Query(query)
	if err != nil {
		// Fall back to generic resources table
		rows, err = s.db.Query("SELECT id FROM resources WHERE resource_type = ?", resourceType)
		if err != nil {
			return nil, err
		}
	}
	defer rows.Close()

	var ids []string
	for rows.Next() {
		var id string
		if err := rows.Scan(&id); err != nil {
			continue
		}
		ids = append(ids, id)
	}
	return ids, rows.Err()
}

// GetLastSyncedAt returns the last sync timestamp for a resource type.
func (s *Store) GetLastSyncedAt(resourceType string) string {
	var ts sql.NullString
	s.db.QueryRow("SELECT last_synced_at FROM sync_state WHERE resource_type = ?", resourceType).Scan(&ts)
	if ts.Valid {
		return ts.String
	}
	return ""
}

// ClearSyncCursors resets all sync state for a full resync.
func (s *Store) ClearSyncCursors() error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	_, err := s.db.Exec("DELETE FROM sync_state")
	return err
}

// Query executes a raw SQL query and returns the rows.
// Used by workflow commands that need custom queries against the local store.
func (s *Store) Query(query string, args ...any) (*sql.Rows, error) {
	return s.db.Query(query, args...)
}

func (s *Store) Count(resourceType string) (int, error) {
	var count int
	err := s.db.QueryRow(
		`SELECT COUNT(*) FROM resources WHERE resource_type = ?`,
		resourceType,
	).Scan(&count)
	return count, err
}

func (s *Store) Status() (map[string]int, error) {
	rows, err := s.db.Query(
		`SELECT resource_type, COUNT(*) FROM resources GROUP BY resource_type ORDER BY resource_type`,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	status := make(map[string]int)
	for rows.Next() {
		var rt string
		var count int
		if err := rows.Scan(&rt, &count); err != nil {
			return nil, err
		}
		status[rt] = count
	}
	return status, rows.Err()
}

// ResolveByName resolves a human-readable name to a UUID from synced data.
// If the input is already a UUID, it is returned as-is.
// matchFields are JSON field names to search against (e.g., "name", "key", "email").
func (s *Store) ResolveByName(resourceType string, input string, matchFields ...string) (string, error) {
	if IsUUID(input) {
		return input, nil
	}

	var matches []string
	// lastErr holds the most recent per-field query/scan/iter failure.
	// If every matchFields entry yielded a failure (or none was safe) and
	// the final `case 0` not-found path is reached, surface lastErr so
	// the user can distinguish a legitimate not-found from a database
	// error masquerading as one.
	var lastErr error
	for _, field := range matchFields {
		// Defense-in-depth: field is interpolated into a json_extract path
		// via fmt.Sprintf and cannot be parameterized. No CLI caller passes
		// user-controlled match fields today, but ResolveByName is a public
		// Store method and the same injection pattern was already patched
		// in ListIDs. Reject anything that isn't a plain identifier
		// ([A-Za-z_][A-Za-z0-9_]*) so a crafted value can't escape the JSON
		// path expression.
		if !isSafeJSONFieldName(field) {
			continue
		}
		query := fmt.Sprintf(
			`SELECT id FROM resources WHERE resource_type = ? AND LOWER(json_extract(data, '$.%s')) = LOWER(?)`,
			field,
		)
		rows, queryErr := s.db.Query(query, resourceType, input)
		if queryErr != nil {
			// A per-field query failure (e.g. malformed JSON in
			// one row's data column) shouldn't poison resolution
			// across the remaining safe fields, but the user
			// gets a chance to see what went wrong via the
			// final error if no matches are found at all.
			lastErr = queryErr
			continue
		}
		// Use a local function so defer fires after each
		// allowlisted field's query, not at function exit. Without
		// this, the loop could pile up unclosed rows on a long
		// matchFields slice and surface a "too many open" SQLite
		// error rather than the natural not-found path.
		func() {
			defer rows.Close()
			for rows.Next() {
				var id string
				if scanErr := rows.Scan(&id); scanErr != nil {
					lastErr = scanErr
					return
				}
				// Deduplicate
				found := false
				for _, m := range matches {
					if m == id {
						found = true
						break
					}
				}
				if !found {
					matches = append(matches, id)
				}
			}
			if iterErr := rows.Err(); iterErr != nil {
				lastErr = iterErr
			}
		}()
	}

	switch len(matches) {
	case 0:
		if lastErr != nil {
			return "", fmt.Errorf("resolving %s %q: %w", resourceType, input, lastErr)
		}
		return "", fmt.Errorf("%s %q not found in local store. Run 'sync' first, or use the UUID directly", resourceType, input)
	case 1:
		return matches[0], nil
	default:
		hint := matches[0]
		if len(matches) > 5 {
			hint = strings.Join(matches[:5], ", ") + "..."
		} else {
			hint = strings.Join(matches, ", ")
		}
		return "", fmt.Errorf("ambiguous: %q matches %d %s entries (%s). Use the exact UUID instead", input, len(matches), resourceType, hint)
	}
}

// UpsertTranscript stores a transcript chunk and updates the FTS index.
func (s *Store) UpsertTranscript(videoID, clipID, kind, text, wordTimingsJSON string) error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()
	if _, err := tx.Exec(
		`INSERT INTO transcripts (video_id, clip_id, kind, text, word_timings_json, fetched_at)
		 VALUES (?, ?, ?, ?, ?, ?)
		 ON CONFLICT(video_id, clip_id, kind) DO UPDATE SET text = excluded.text, word_timings_json = excluded.word_timings_json, fetched_at = excluded.fetched_at`,
		videoID, clipID, kind, text, wordTimingsJSON, time.Now(),
	); err != nil {
		return err
	}
	rowid := ftsRowID(videoID + "/" + clipID + "/" + kind)
	if _, err := tx.Exec(`DELETE FROM transcripts_fts WHERE rowid = ?`, rowid); err != nil {
		fmt.Fprintf(os.Stderr, "warning: transcripts_fts cleanup failed: %v\n", err)
	}
	if _, err := tx.Exec(
		`INSERT INTO transcripts_fts (rowid, video_id, clip_id, kind, text) VALUES (?, ?, ?, ?, ?)`,
		rowid, videoID, clipID, kind, text,
	); err != nil {
		fmt.Fprintf(os.Stderr, "warning: transcripts_fts insert failed: %v\n", err)
	}
	return tx.Commit()
}

// SearchTranscripts runs an FTS5 query over cached transcripts and returns hits.
type TranscriptHit struct {
	VideoID string `json:"video_id"`
	ClipID  string `json:"clip_id"`
	Kind    string `json:"kind"`
	Snippet string `json:"snippet"`
}

func (s *Store) SearchTranscripts(query string, limit int) ([]TranscriptHit, error) {
	if limit <= 0 {
		limit = 25
	}
	rows, err := s.db.Query(
		`SELECT video_id, clip_id, kind, snippet(transcripts_fts, 3, '[', ']', '...', 16)
		 FROM transcripts_fts WHERE transcripts_fts MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []TranscriptHit
	for rows.Next() {
		var h TranscriptHit
		if err := rows.Scan(&h.VideoID, &h.ClipID, &h.Kind, &h.Snippet); err != nil {
			return nil, err
		}
		out = append(out, h)
	}
	return out, rows.Err()
}

// CountTranscripts returns total transcript rows.
func (s *Store) CountTranscripts() (int, error) {
	var n int
	err := s.db.QueryRow(`SELECT COUNT(*) FROM transcripts`).Scan(&n)
	return n, err
}

// SumTranscriptWords returns the approximate total word count across all cached transcripts.
func (s *Store) SumTranscriptWords() (int, error) {
	rows, err := s.db.Query(`SELECT text FROM transcripts`)
	if err != nil {
		return 0, err
	}
	defer rows.Close()
	total := 0
	for rows.Next() {
		var t sql.NullString
		if err := rows.Scan(&t); err != nil {
			return 0, err
		}
		if t.Valid {
			total += len(strings.Fields(t.String))
		}
	}
	return total, rows.Err()
}

// LatestSyncedAt returns the most recent last_synced_at across all sync_state rows.
func (s *Store) LatestSyncedAt() (time.Time, error) {
	var t sql.NullTime
	err := s.db.QueryRow(`SELECT MAX(last_synced_at) FROM sync_state`).Scan(&t)
	if err == sql.ErrNoRows || !t.Valid {
		return time.Time{}, nil
	}
	if err != nil {
		return time.Time{}, err
	}
	return t.Time, nil
}
